using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we configured HasDiscriminator("Discriminator")
        // to preserve the old property name. Without that opt-in, EF Core 9 would write "$type" instead,
        // and this query would silently return zero results against existing documents.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider no longer supports synchronous I/O (ToList, SaveChanges, etc.).
        // All calls must use async equivalents.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

